function mergeCopy<T extends object>(base: T, override?: DeepPartial<T>): T {
  if (!override) {
    return structuredClone(base);
  }

  const result = structuredClone(base) as Record<string, unknown>;

  for (const [key, value] of Object.entries(override)) {
    if (value && typeof value === "object" && !Array.isArray(value)) {
      result[key] = mergeCopy(result[key] as Record<string, unknown>, value as DeepPartial<Record<string, unknown>>);
      continue;
    }

    result[key] = value as unknown;
  }

  return result as T;
}

export function getSiteCopy(language: SiteLanguageCode = DEFAULT_SITE_LANGUAGE): SiteCopy {
  return mergeCopy(englishCopy, overrides[language]) as SiteCopy;
}